0; bottom:0;\n    width:var(--sidebar-w); background:#fff;\n    border-right:1px solid #e2e8f0;\n    overflow-y:auto; z-index:50; padding:12px 0;\n    transition:transform .3s ease;\n}\n.sidebar::-webkit-scrollbar { width:4px; }\n.sidebar::-webkit-scrollbar-thumb { background:#cbd5e1; border-radius:4px; }\n.nav-group { margin-bottom:4px; }\n.nav-group-title {\n    display:flex; align-items:center; gap:8px;\n    padding:8px 16px; font-size:11px; font-weight:700;\n    text-transform:uppercase; color:#94a3b8; letter-spacing:.8px;\n    cursor:pointer; user-select:none;\n}\n.nav-group-title:hover { color:#64748b; }\n.nav-group-title .arrow { font-size:10px; transition:transform .2s; }\n.nav-group.collapsed .arrow { transform:rotate(-90deg); }\n.nav-group.collapsed .nav-items { display:none; }\n.nav-items { padding:0 8px; }\n.nav-items a {	kms_guide.html	[]	2026-04-16 07:15:19	2026-04-16 07:15:19
