px; font-weight:600;\n    text-align:left;\n}\n.func-table tbody tr { transition:background .15s; }\n.func-table tbody tr:hover { background:#f8fafc; }\n.func-table tbody td {\n    padding:10px 16px; border-bottom:1px solid #e2e8f0;\n}\n.func-table tbody tr:last-child td { border-bottom:none; }\n.func-badge {\n    display:inline-block;\n    padding:5px 14px; border-radius:20px; font-size:12px;\n    font-weight:600; color:#fff; white-space:nowrap;\n    min-width:170px; text-align:center; box-sizing:border-box;\n}\n\n/* CUSTOM LIST (for grouped bullet items) */\n.custom-list { list-style:none; padding:0; margin:8px 0; }\n.custom-list li {\n    margin:6px 0; padding:6px 12px 6px 28px	kms_guide.html	[]	2026-04-16 07:15:19	2026-04-16 07:15:19
