LBAR (dark mode, font size, print) */\n.toolbar {\n    position:fixed; top:var(--header-h); right:0;\n    display:flex; flex-direction:column; gap:6px;\n    padding:8px; z-index:90;\n}\n.toolbar button {\n    width:36px; height:36px; border-radius:10px; border:1px solid #e2e8f0;\n    background:#fff; color:#64748b; cursor:pointer; font-size:14px;\n    display:flex; align-items:center; justify-content:center;\n    transition:all .2s; box-shadow:0 1px 4px rgba(0,0,0,0.06);\n}\n.toolbar button:hover {\n    background:var(--brand); color:#fff; border-color:var(--brand);\n    box-shadow:0 4px 12px var(--brand-shadow);\n}\n.toolbar button.active-btn {\n    background:var(--brand); color:#fff; border-color:var(--brand);\n}\n\n/* DARK MODE */\nbody.dark {\n    background:#0f172a; color:#e2e8f0;\n}\nbody.dark .sidebar {\n    background:#1e293b; border-color:#334155;\n}\nbody.dark .header {\n    background:var(--brand-dark-header); box-shadow:	kms_guide.html	[]	2026-04-16 07:15:19	2026-04-16 07:15:19
