br/>45<br/>45<br/>45<br/>45</td><td></td></tr></table>\n\n![](images/11_0.jpg)\n\nBẢNG THAM CHIỂU QUY ĐỊ MỘT SỐ BẢNG HOẶC CHỨNG CHỈ NGOẠI NGỮ TƯƠNG ĐƯƠNG BẢC 3 VÀ BẢC 4 KHUNG NẬNG LỰC NGOẠI NGỮ 6 BẢC DÙNG CHO VIỆT NAM ÁP DỤNG TRONG TUYỂN SINH VÀ ĐÀO TẠO TRÌNH ĐỘ THẬC SĨ\n\n(Kèm theo Thông báo số 915/TB-HV ngày 25 tháng 9 năm 2025 của Giám đốc Hộc	975tb Thong bao tuyen sinh Thac si Dot 2 nam 2025.pdf	["default:extract:4df2f8ba8ecf3e3002a3843521806d8c", "default:extract:1a99348a6bea5344530179ec2ffe2914"]	2026-04-16 02:05:49	2026-04-16 02:06:34
chunk-175717fb1c315ccd62bb0c4860970bf3	0b44af39-1304-4610-8917-fbd198023611	doc-44f531d34837f463a26f19632d8f6193	1	800	Chuyên ngành đào tạo</td><td rowspan="2">Mã ngành</td><td colspan="2">Chỉ tiêu (Dự kiến)</td><td rowspan="2">Môn xét tuyển (*)</td></tr><tr><td>BVH</td><td>BVS</td></tr><tr><td>Kỹ thuật viễn thông</td><td>8520208</td><td>27</td><td>25</td><td rowspan="5">Môn Cơ sở ngành<br/>(Lựa chọn 01 môn trong<br/>03 môn tương ứng với<br/>chuyên ngành)</td><td rowspan="5">Môn Chuyên ngành<br/>(Lựa chọn 01 môn trong 03 môn tương<br/>ứng với chuyên ngành)</td></tr><tr><td>Kỹ thuật điện tử</td><td>8520203</td><td>13</td><td></td></tr><tr><td>Hệ thống thông tin</td><td>8480104</td><td>45</td><td>17</td></tr><tr><td>Khoa học máy tính</td><td>8480101</td><td>26</td><td></td></tr><tr><td>Quản trị kinh doanh</td><td>8340101</td><td>33</td><td></td></tr><tr><td>Tổng</td><td></td><td>144</td><td>42</td><td></td></tr></table>\n\n(*) : Danh sách các môn xét tuyển tại Phụ lục 1 kèm theo Thông báo tuyển sinh này \n\nIV. ĐIỀU KIỆN DỰ TUYỂN:\n\nNgười dự tuyển trình độ thạc sĩ tại Học viện phải có đầy đủ các điều kiện sau: \n\n1. Điều kiện về văn bằng đại học:\n\na) Đã tốt nghiệp hoặc đã đủ điều kiện công nhận tốt nghiệp đại học (hoặc trình độ tương đương trở lên) ngành đúng, ngành phù hợp với chuyên ngành đăng ký dự tuyển tương ứng; \n\nb) Người đã tốt nghiệp đại học ngành/chuyên ngành gần với chuyên ngành đăng ký dự tuyển phải học Bổ sung kiến thức trước khi dự tuyển. \n\nc) Đối với chuyên ngành Quản trị kinh doanh, người đang làm công tác quản trị, quản lý và có văn bằng tốt nghiệp đại học không thuộc ngành đúng hoặc gần nhưng liên quan trực tiếp tới chuyên môn, nghề nghiệp của lĩnh vực quản trị, quản lý thì được đăng ký xét tuyển; đồng thời phải học Bổ sung kiến thức trước khi dự tuyển. \n\nd) Người có bằng tốt nghiệp đại học do cơ sở giáo dục nước ngoài cấp ngoài các điều kiện nêu trên phải có giấy chứng nhận văn bằng tốt nghiệp của Cục Quản lý chất lượng - Bộ Giáo dục và Đào tạo. \n\nDanh mục ngành đúng, ngành phù hợp, ngành gần, ngành khác; Danh mục các môn học Bổ sung kiến thức (BSKT) như Phụ lục II kèm theo. \n\n2. Điều kiện về năng lực tiếng Anh đối với người dự tuyển:\n\nỨng viên đáp ứng yêu cầu năng lực tiếng Anh để được đăng ký dự tuyển khi có một trong các văn bằng, chứng chỉ sau: \n\na) Bằng tốt nghiệp trình độ đại học trở lên ngành ngôn ngữ tiếng Anh; hoặc bằng tốt nghiệp trình độ đại học trở lên mà chương trình được thực hiện chủ yếu bằng tiếng Anh; \n\nb) Bằng tốt nghiệp trình độ đại học trở lên do Học viện Công nghệ Bưu chính Viễn thông cấp trong thời gian không quá 02 năm tính đến ngày đăng ký dự tuyển mà\n\nchuẩn đầu ra của chương trình đã đáp ứng yêu cầu tiếng Anh đạt trình độ	975tb Thong bao tuyen sinh Thac si Dot 2 nam 2025.pdf	["default:extract:b25c5286d28946d260886fb6ea9f832e", "default:extract:bb7d80db12598199f2b0b2474fc73a82"]	2026-04-16 02:05:49	2026-04-16 02:06:35
chunk-a9cca4d369d6d74eb8bd3e1d36854697	48c2de82-e3d7-444b-9619-ce9406362e59	doc-6ac70b33ea66350fec1d55e5cd12a5e8	24	800	file:';\n    var videoId = vid.getAttribute('data-video-id') || '';\n    if(!videoId) return;\n    var img = new Image();\n    img.onload = function(){\n        if(!isLocal){\n            var link = vid.querySelector('.video-thumb-link');\n            if(link && wrapper){\n                var iframe = document.createElement('iframe');\n                iframe.src = 'https://www.youtube.com/embed/' + videoId;\n                iframe.title = 'Video';\n                iframe.allow = 'accelerometer;autoplay;clipboard-write;encrypted-media;gyroscope;picture-in-picture';\n                iframe.allowFullscreen = true;\n                iframe.style.cssText = 'position:absolute;top:0;left:0;width:100%;height:100%;border:none;';\n                var newWrapper = wrapper.cloneNode(false);\n                newWrapper.style.background = '#000';\n                newWrapper.appendChild(iframe);\n                link.replaceWith(newWrapper);\n            }\n        } else {\n            var thumb = document.getElementById('video-thumb');\n            if(thumb) thumb.src = 'https://img.youtube.com/vi/' + videoId + '/hqdefault.jpg';\n        }\n        vid.style.display = '';\n    };\n    img.onerror = function(){ vid.remove(); };\n    img.src = 'https://img.youtube.com/vi/' + videoId + '/hqdefault.jpg?_t=' + Date.now();\n})();\n\n// ============================================\n// BACK TO TOP\n// ============================================\nvar backTop = document.getElementById('backTop');\nwindow.addEventListener('scroll', function() {\n    backTop.classList.toggle('show', window.scrollY > 400);\n});\n\n// ============================================\n// SIDEBAR ACTIVE STATE ON SCROLL\n// ============================================\nvar navTargets = document.querySelectorAll('.section[id], .feature-card[id]');\nvar navLinks = document.querySelectorAll('.nav-items a');\nvar obs = new IntersectionObserver(function(entries) {\n    entries.forEach(function(e) {\n        if (e.isIntersecting) {\n            navLinks.forEach(function(a) {\n                a.classList.toggle('active', a.getAttribute('href') === '#' + e.target.id);\n            });\n        }\n    });\n}, { rootMargin: '-20% 0px -70% 0px' });\nnavTargets.forEach(function(s) { obs.observe(s); });\n\n// ============================================\n// NAV GROUP COLLAPSE TOGGLE\n// ============================================\ndocument.querySelectorAll('.nav-group-title').forEach(function(t) {\n    t.addEventListener('click', function() {\n        t.parentElement.classList.toggle('collapsed');\n    });\n});\n\n// ============================================\n// SIDEBAR LINK CLICK: open card + close mobile\n// ============================================\ndocument.querySelectorAll('.nav-items a').forEach(function(a) {\n    a.addEventListener('click', function() {\n        var id = a.getAttribute('href');\n        if (id) id = id.substring(1);\n        var target = id && document.getElementById(id);\n        if (target && target.classList.contains('feature-card') && !target.classList.contains('open')) {\n            target.classList.add('open');\n        }\n        if (window.innerWidth <= 900) {\n            document.querySelector('.sidebar').classList.remove('open');\n        }\n    });\n});\n\n// ============================================\n// OPEN FIRST FEATURE CARD BY DEFAULT\n// ============================================\nvar firstCard = document.querySelector('.feature-card');\nif (firstCard) firstCard.classList.add('open');\n\n// ============================================\n// LIGHTBOX — add zoom button + click handler\n// ============================================\ndocument.querySelectorAll('.img-container').forEach(function(c) {\n    var img = c.querySelector('img');\n    if (!img) return;\n    var btn = document.createElement('button');\n    btn.className = 'img-zoom';\n    btn.innerHTML = '⛶';\n    btn.onclick = function(e) { e.stopPropagation();	kms_guide.html	[]	2026-04-16 07:15:19	2026-04-16 07:15:19
chunk-522484105f8825c7259b2b24601b9618	0b44af39-1304-4610-8917-fbd198023611	doc-44f531d34837f463a26f19632d8f6193	2	800	Bằng tốt nghiệp trình độ đại học trở lên ngành ngôn ngữ tiếng Anh; hoặc bằng tốt nghiệp trình độ đại học trở lên mà chương trình được thực hiện chủ yếu bằng tiếng Anh; \n\nb) Bằng tốt nghiệp trình độ đại học trở lên do Học viện Công nghệ Bưu chính Viễn thông cấp trong thời gian không quá 02 năm tính đến ngày đăng ký dự tuyển mà\n\nchuẩn đầu ra của chương trình đã đáp ứng yêu cầu tiếng Anh đạt trình độ Bậc 3 trở lên theo Khung năng lực ngoại ngữ 6 bậc dùng cho Việt Nam;\n\nc) Mбург trong các văn bằng hoặc chứng chỉ tiếng Anh đạt trình độ tương đương Bậc 3 trở lên theo Khung năng lực ngoại ngữ 6 bậc dùng cho Việt Nam hoặc các chứng chỉ khác do Bộ Giáo dục và Đào tạo công bố, còn hiệu lực tính đến ngày đăng ký dư tuyển (Phụ lực 3).\n\nd) Ủng viện dư tuyển không có văn bằng, chứng chỉ tiếng Anh theo quy định hoặc có nhưng đã hết thời hạn, phải tham dự kỳ thi đánh giá năng lực tiếng Anh do Hộc viện phối hợp với một trong số các đơn vị được Bộ Giáo dục và Đào tạo cho phép tổ chức thi và cấp chứng chỉ tiếng Anh theo khung năng lực ngoại ngữ 6 bậc dùng cho Việt nam tổ chức (nếu có) và phải đạt yếu câu theo quy định trở lên. Cụ thể là:\n\nỦng viện tham gia thi 04 kỹ năng Nghe, Độc, Viết, Nói (môi kỹ năng được đánh giá trên thang điều trị 0 đến 10, làm trơn đến 0,5 điều) trên máy, trực tiếp theo định đăng để thi đánh giá năng lực tiếng Anh từ bắc 3 đến bắc 5 theo Khung năng lực ngoại ngữ 6 bắc dùng cho Việt Nam (ban hành kèm theo Quyết định số 729/QĐ-BGDĐT ngày 11/03/2015 của Bộ trưởng Bộ Giáo dục và Đào tạo). Các ứng viện đạt điều trị trung bình của 04 kỹ năng từ 4.0 trở lên sẽ được công nhận đạt năng lực tiếng Anh (tương đương với bắc 3 theo Khung năng lực ngoại ngữ 6 bắc dùng cho Việt Nam) để xét tuyển vào học các chương trình đào tạo trình độ thực sĩ tại Hộc viện).\n\nThời gian thi dư kiến: Tháng 11.2025\n\nThi sinh chưa có văn bằng chứng chỉ ngoại ngữ đùng theo yếu câu dư tuyển, yếu câu đăng ký thi đánh giá năng lực ngoại ngữ tại Khoa đào tạo Sau đại học (tàng 10 nhà A2). Điện thoại: 024.33512254)\n\nLý lịch bản thân rõ ràng, không trong thời gian thi hành kỳ luật từ mức cánh cáo trở lên và không trong thời gian thi hành án hình sự, được cơ quan quản lý nhân sự nơi đang làm việc hoặc chính quyền địa phương cư trú xác nhận.\n\nCó đủ sức khỏe để học tập\n\nNộp hồ sơ đảy đủ, đúng hạn theo quy định tại Mục VII của thông báo này.\n\nV. ĐỐI TƯỢNG VÀ CHÍNH SÁCH ƯU TIÊN:\n\nĐối tượng ưu tiên:\n\na. Người có thời gian công tác liên tục từ 2 năm trở lên (tính đến ngày hết hạn nộp hồ sơ đăng ký xét tuyển) tại các địa phương được quy định là Khu vực 1 trong Quy chế tuyển sinh đại học hệ chính quy hiện hành.\n\nb. Thương bình, bình bình, người có thể chứng nhận được hưởng chính sách như thương bình.\n\nc. Anh hùng lực lượng vũ	975tb Thong bao tuyen sinh Thac si Dot 2 nam 2025.pdf	["default:extract:a0de2c9886368422b974a9b98d0bd87d", "default:extract:5cc6f9c2ac23319f244b81ad055a27b3"]	2026-04-16 02:05:49	2026-04-16 02:06:26
chunk-391f25a98463d6d97932676200db4489	0b44af39-1304-4610-8917-fbd198023611	doc-44f531d34837f463a26f19632d8f6193	5	800	khi nộp hồ so ĐKXT.\n\nHộc viện không hoàn trả hồ so ĐKXT, lệ phí tuyển sinh khi thi sinh xin rút đơn ĐKXT\n\nIX. THỜI GIAN TỔ CHÚC XÉT TUYỂN\n\nThời gian xét tuyển và nhập học: Dư kiến giữa tháng 12/2025.\n\n2. Hộc Bổ sung kiến thức:\n\nHộc viện tổ chức lóp học BSKT: Từ 22/09/2025 đến 30/11/2025\n\n(Thí sinh khi đến đăng ký học BSKT mang theo bằng tốt nghiệp đại học và bằng điều dệ xác định số môn cần phải học BSKT).\n\nCác trường hợp đã học và được công nhận hoàn thành chương trình BSKT của Hộc viện trong thời gian 12 tháng (tính từ ngày có quyết định công nhận hoàn thành chương trình đến ngày nộp hồ sơ đăng ký xét tuyển) được miễn học các môn BSKT của ngành tương ứng.\n\nX. ĐỊA CHỈ LIÊN HỆ:\n\nTại Phía Bắc:\n\nVăn phòng Giao dịch một cửa (Bộ phận Tuyên sinh)\n\nKm10 đường Nguyễn Trải, Quận Hà Đông, Hà Nội\n\nĐiện thoại: 024.33528122; Fax: 024.33829236.\n\nEmail: tuyensinh@ptit.edu.vn\n\nWebsite: https://tuyensinh.ptit.edu.vn\n\nTại Phía Nam:\n\nPhòng Đào tạo và Khoa học Công nghệ - Cơ sở Hộc viện tại Tp. Hồ Chí Minh\n\nSố 11 Nguyễn Đình Chiêu, Quận 1, Tp. Hồ Chí Minh\n\nĐiện thoại: 028.38297220; Fax: 028.39105510\n\nEmail: tuyensinh@ptithcm.edu.vn\n\nWebsite: https://tuyensinh.ptit.edu.vn; https://ptithcm.edu.vn\n\nMôi thông tin chi tiết và mãu hồ so đăng ký dư thi thí sinh có thể xem và tài về tại trang thông tin điện tử của Hộc viện Công nghệ Bưu chính Viễn thông theo địa chỉ: https://tuyensinh.ptit.edu.vn.\n\nNoi nhận:\n\nBộ GD&ĐT (để b/c);\n\nBộ KH&CN (để b/c);\n\nBan Giám đốc Hộc viện (để b/c);\n\nCác đơn vị trực thuốc Hộc viện;\n\nCác Phòng, Ban, Khoa, Trung tâm của Hộc viện;\n\nLuru VT, ĐT.\n\nKT. GIÁM ĐÓC\n\nHỎC PHỐ GIÁM ĐÓC\n\nHỎC VIỆN\nCÔNG NGHỆ\nBỦU CHÍNH\nVIỆN THỊNG\n\nPGSTS. Trần Quang Anh\n\nPhụ lục I\n\nDANH MỤC CÁC CHUYÊN NGÀNH TUYỂN SINH VÀ\n\nDANH MỤC CÁC MÔN XÉT TUYỂN TRỊNH ĐỘ THẤC SĨ\n\n(Kèm theo Thông báo số 475/TB-HV ngày 22 tháng 9 năm 2025 của Giám đốc Hộc viện)\n\n<table><tr><td rowspan="3">TT</td><td rowspan="3">Chuyên ngành tuyển sinh</td><td colspan="4">Danh mục các môn xét tuyển</td></tr><tr><td>Môn Cơ sở ngành (Chơn 1 trong 3 môn tương ứng với chuyên ngành đăng ký dư tuyển)</td><td>Tín chí/ ĐVHT</td><td>Môn Chuyên ngành (Chơn 1 trong	975tb Thong bao tuyen sinh Thac si Dot 2 nam 2025.pdf	["default:extract:affbcc38acbf279f6839a3a0bb5f5027", "default:extract:7554840218cae1cebf25026548e739dc"]	2026-04-16 02:05:49	2026-04-16 02:06:27
chunk-b8289428f9359f375f34ba533c70f965	0b44af39-1304-4610-8917-fbd198023611	doc-44f531d34837f463a26f19632d8f6193	4	800	thí sinh có điều cao từ trên xuống và đảm bảo ngưỡng chất lượng.\n\nGhi chú: Hộc viện chỉ tổ chức lóp học khi môi lóp có từ 25 học viện trở lên. Nếu số lượng ít hon 25 học viện / lóp thì các học viện đã trùng tuyển có thể được xem xét chuyển sang chuyên ngành khác phù hợp (cùng các môn xét tuyển) hoặc có thể bảo lưu kết quả trùng tuyển và học cùng với đợt tuyển sinh tiếp theo.\n\nVII. HỎ SƠ TUYỂN SINH:\n\n1. Hồ sơ đăng ký dư thi gồm:\n\n1) 01 Đơn đăng ký dư tuyển trình độ thạc sĩ (theo mẫu)\n\n2) 01 Sơ yếu lý lịch (có xác nhận của cơ quan quản lý hoặc chính quyền địa phương)\n\n3) 01 Bản sao công chứng các loại giấy tờ sau:\n\na) Bàng và bằng điều tốt nghệp đại học;\n\nb) Các loại giấy tờ xác nhận đổi tương ưu tiên (nếu có).\n\nc) Giấy chứng nhận hoàn thành chương trình bổ sung kiến thúc của Hộc viện trong thời hạn 01 năm kế từ ngày cấp đến ngày đăng ký xét tuyển (nếu có);\n\nd) Giấy khai sinh;\n\n4) Chứng chỉ tiếng Anh theo quy định (nếu có).\n\n5) 01 Công văn cử đi dự thi của Thủ trưởng cơ quan quản lý đổi với thi sinh do cơ quan cử đi (không yếu câu đổi với thi sinh tự do).\n\n6) Giấy xác nhận vị trí công tác quản lý hoặc Hộp đồng lao động/ Quyết định tiếp nhận công tác, Quyết định bỏ nhiệm (đối với thi sinh cần minh chứng về chuyên môn, nghệ nghiệp liên quan đến lĩnh vực quản trị, quản lý);\n\n7) 04 Ánh mâu cõ 3×4cm (ghi rõ hộ tên và ngày sinh của thi sinh ở mật sau) và 02 phong bì dán tem và để sẵn địa chỉ liên hệ của thi sinh;\n\n8) 01 Giấy chứng nhận đủ sức khóe để học tập của bình viện đã khoa trong thời hạn 6 tháng kế từ ngày ký đến ngày nộp hồ so;\n\n9) Giấy chứng nhận của Cục Quản lý chất lượng - Bộ Giáo dục và Đào tạo về văn bằng tốt nghiệp đại học do cơ sở giáo dục nước ngoài cấp (nếu là văn bằng tốt nghiệp đại học do Cơ sở giáo dục đại học nước ngoài cấp).\n\n2. Thời gian phát hành và tiếp nhận hồ sơ xét tuyển: Từ ngày 15/09/2025 đến ngày 10/12/2025\n\nVIII. KINH PHÍ:\n\nPhát hành hồ so: 60.000 đồng / hồ so\n\nPhí đăng ký xét tuyển: 60.000 đồng / hồ so\n\nPhí xét tuyển: 120.000 đồng / môn\n\nKinh phí học bổ sung kiến thúc: 650.000 đồng /tín chí\n\nHộc phí (dư kiến): 900.000 đồng/tín chí đổi với khối ngành kinh tế; 1.000.000 đồng/tín chí đổi với khối ngành kỹ thuật\n\nLưu ý: - Phí đăng ký xét tuyển và phí xét tuyển nộp một lần khi nộp hồ so ĐKXT.\n\nHộc viện không hoàn trả hồ so ĐKXT, lệ phí tuyển sinh khi thi sinh xin rút đơn ĐKXT\n\nIX. THỜI GIAN TỔ CHÚC XÉT TUYỂN\n\nThời gian xét tuyển và nhập học: Dư kiến giữa tháng 12/2025.\n\n2. Hộc Bổ sung kiến thức:\n\nHộc viện tổ chức lóp học BSKT: T	975tb Thong bao tuyen sinh Thac si Dot 2 nam 2025.pdf	["default:extract:362cbc3a5954784296d49a070600caf8", "default:extract:48d4655490e7e166453729f2d2e618d5"]	2026-04-16 02:05:49	2026-04-16 02:06:35
chunk-0d77282911946d24d1d0a01dab60ebac	48c2de82-e3d7-444b-9619-ce9406362e59	doc-6ac70b33ea66350fec1d55e5cd12a5e8	25	800	Card) firstCard.classList.add('open');\n\n// ============================================\n// LIGHTBOX — add zoom button + click handler\n// ============================================\ndocument.querySelectorAll('.img-container').forEach(function(c) {\n    var img = c.querySelector('img');\n    if (!img) return;\n    var btn = document.createElement('button');\n    btn.className = 'img-zoom';\n    btn.innerHTML = '⛶';\n    btn.onclick = function(e) { e.stopPropagation(); openLightbox(img); };\n    c.appendChild(btn);\n    img.onclick = function() { openLightbox(img); };\n});\n\n// ============================================\n// SCROLL REVEAL\n// ============================================\nvar revealObs = new IntersectionObserver(function(entries) {\n    entries.forEach(function(e) {\n        if (e.isIntersecting) {\n            e.target.classList.add('visible');\n            revealObs.unobserve(e.target);\n        }\n    });\n}, { threshold:0.08 });\ndocument.querySelectorAll('.reveal').forEach(function(el) { revealObs.observe(el); });\n\n// ============================================\n// READING PROGRESS BAR\n// ============================================\nvar progressBar = document.getElementById('progressBar');\nwindow.addEventListener('scroll', function() {\n    var h = document.documentElement.scrollHeight - window.innerHeight;\n    var pct = h > 0 ? (window.scrollY / h) * 100 : 0;\n    progressBar.style.width = pct + '%';\n});\n\n// ============================================\n// DARK MODE\n// ============================================\nfunction toggleDark() {\n    document.body.classList.toggle('dark');\n    var isDark = document.body.classList.contains('dark');\n    document.getElementById('darkBtn').textContent = isDark ? '\\u2600\\uFE0F' : '\\uD83C\\uDF19';\n    localStorage.setItem(LS_PREFIX + '-dark', isDark ? '1' : '0');\n}\nif (localStorage.getItem(LS_PREFIX + '-dark') === '1') {\n    document.body.classList.add('dark');\n    document.getElementById('darkBtn').textContent = '\\u2600\\uFE0F';\n}\n\n// ============================================\n// FONT SIZE CONTROL\n// ============================================\nvar currentFontSize = parseInt(localStorage.getItem(LS_PREFIX + '-fontsize') || '15');\ndocument.body.style.fontSize = currentFontSize + 'px';\nfunction changeFontSize(delta) {\n    currentFontSize = Math.max(12, Math.min(22, currentFontSize + delta));\n    document.body.style.fontSize = currentFontSize + 'px';\n    localStorage.setItem(LS_PREFIX + '-fontsize', currentFontSize);\n}\n\n// ============================================\n// READ STATE (mark as read)\n// ============================================\nfunction saveReadState() {\n    var readIds = [];\n    document.querySelectorAll('.feature-card.read').forEach(function(c) {\n        if (c.id) readIds.push(c.id);\n    });\n    localStorage.setItem(LS_PREFIX + '-read', JSON.stringify(readIds));\n}\nfunction loadReadState() {\n    try {\n        var readIds = JSON.parse(localStorage.getItem(LS_PREFIX + '-read') || '[]');\n        readIds.forEach(function(id) {\n            var el = document.getElementById(id);\n            if (el) el.classList.add('read');\n        });\n    } catch(e) {}\n}\nloadReadState();\n\n// ============================================\n// BADGE COUNTS ON FEATURE CARDS\n// ============================================\ndocument.querySelectorAll('.feature-card').forEach(function(card) {\n    var body = card.querySelector('.feature-body');\n    if (!body) return;\n    var steps = body.querySelectorAll('.step-box').length;\n    var imgs = body.querySelectorAll('.img-container').length;\n    if (steps || imgs) {\n        var badge = document.createElement('span');\n        badge.className = 'f	kms_guide.html	[]	2026-04-16 07:15:19	2026-04-16 07:15:19
chunk-380f727ddbd6ffade9aafc3f57fbae35	48c2de82-e3d7-444b-9619-ce9406362e59	doc-6ac70b33ea66350fec1d55e5cd12a5e8	26	800	===========\n// BADGE COUNTS ON FEATURE CARDS\n// ============================================\ndocument.querySelectorAll('.feature-card').forEach(function(card) {\n    var body = card.querySelector('.feature-body');\n    if (!body) return;\n    var steps = body.querySelectorAll('.step-box').length;\n    var imgs = body.querySelectorAll('.img-container').length;\n    if (steps || imgs) {\n        var badge = document.createElement('span');\n        badge.className = 'f-badge';\n        var parts = [];\n        if (steps) parts.push(steps + ' buoc');\n        if (imgs) parts.push(imgs + ' anh');\n        badge.textContent = parts.join(' \\u00B7 ');\n        var title = card.querySelector('.f-title');\n        if (title) title.after(badge);\n    }\n});\n\n// ============================================\n// LIGHTBOX WITH PREV/NEXT\n// ============================================\nvar lbImages = [];\nvar lbIndex = 0;\ndocument.querySelectorAll('.img-container img').forEach(function(img) {\n    lbImages.push(img);\n});\n\nfunction openLightbox(img) {\n    var lb = document.getElementById('lightbox');\n    lbIndex = lbImages.indexOf(img);\n    if (lbIndex === -1) lbIndex = 0;\n    showLightboxImage();\n    lb.classList.add('show');\n}\n\nfunction showLightboxImage() {\n    var img = lbImages[lbIndex];\n    if (!img) return;\n    document.getElementById('lb-img').src = img.src;\n    var cap = img.closest('.img-container') ? img.closest('.img-container').nextElementSibling : null;\n    var capText = (cap && cap.classList.contains('img-caption')) ? cap.textContent :\n        (img.closest('.img-container') && img.closest('.img-container').previousElementSibling &&\n         img.closest('.img-container').previousElementSibling.classList.contains('img-caption') ?\n         img.closest('.img-container').previousElementSibling.textContent : img.alt || '');\n    document.getElementById('lb-cap').textContent = capText;\n    document.getElementById('lb-counter').textContent = (lbIndex + 1) + ' / ' + lbImages.length;\n}\n\nfunction navLightbox(dir) {\n    lbIndex = (lbIndex + dir + lbImages.length) % lbImages.length;\n    showLightboxImage();\n}\n\nfunction closeLightbox() {\n    document.getElementById('lightbox').classList.remove('show');\n    var img = lbImages[lbIndex];\n    if (img) {\n        var card = img.closest('.feature-card');\n        if (card && !card.classList.contains('open')) {\n            card.classList.add('open');\n        }\n        setTimeout(function() {\n            img.scrollIntoView({ behavior:'smooth', block:'center' });\n        }, 50);\n    }\n}\n\n// ============================================\n// KEYBOARD NAVIGATION\n// ============================================\ndocument.addEventListener('keydown', function(e) {\n    if (e.key === 'Escape') closeLightbox();\n    var lb = document.getElementById('lightbox');\n    if (lb.classList.contains('show')) {\n        if (e.key === 'ArrowLeft') navLightbox(-1);\n        if (e.key === 'ArrowRight') navLightbox(1);\n        return;\n    }\n    if ((e.ctrlKey || e.metaKey) && e.key === 'k') {\n        e.preventDefault();\n        document.getElementById('searchInput').focus();\n    }\n});\n\n// ============================================\n// SEARCH FUNCTIONALITY\n// ============================================\nfunction searchContent(query) {\n    var resultsDiv = document.getElementById('searchResults');\n    if (!query || query.length < 2) {\n        resultsDiv.style.display = 'none';\n        resultsDiv.innerHTML = '';\n        return;\n    }	kms_guide.html	[]	2026-04-16 07:15:19	2026-04-16 07:15:19
