'';\n        var id = sec.id;\n        if (id && title.toLowerCase().indexOf(q) !== -1) {\n            var exists = results.find(function(r) { return r.id === id; });\n            if (!exists) results.push({ title: title, id: id, snippet: '' });\n        }\n    });\n    if (results.length === 0) {\n        resultsDiv.innerHTML = '<div style="padding:12px 14px;color:#94a3b8;font-size:13px;">Khong tim thay ket qua</div>';\n    } else {\n        resultsDiv.innerHTML = results.map(function(r) {\n            return '<a href="#' + r.id + '" onclick="closeSearch()" style="display:block;padding:10px 14px;text-decoration:none;color:#1e293b;border-bottom:1px solid #f1f5f9;transition:background .15s;font-size:13px;" onmouseover="this.style.background=\\'#f8fafc\\'" onmouseout="this.style.background=\\'#fff\\'">' +\n            '<div style="font-weight:600;margin-bottom:2px;">' + r.title + '</div>' +\n            (r.snippet ? '<div style="font-size:12px;color:#94a3b8;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">' + r.snippet.replace(new RegExp('(' + query.replace(/[.*+?^${}()|[\\]\\\\]/g,'\\\\$&') + ')','gi'), '<mark style="background:#fef08a;border-radius:2px;padding:0 1px;">$1</mark>') + '</div>' : '') +\n            '</a>';\n        }).join('');\n    }\n    resultsDiv.style.display = 'block';\n}\nfunction closeSearch() {\n    document.getElementById('	kms_guide.html	[]	2026-04-16 07:15:19	2026-04-16 07:15:19
